import React, { useState, useEffect } from 'react';
import { getEventsByOrganiser, getSlotsByEvent, getAllLocations, createSlot, updateSlot, deleteSlot } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const STATUS_BADGE = { AVAILABLE: 'badge-success', HOUSEFULL: 'badge-warning', CANCELLED: 'badge-danger' };

const AdminSlotsPage = () => {
  const { user } = useAuth();
  const [slots, setSlots]           = useState([]);
  const [events, setEvents]         = useState([]);
  const [locations, setLocations]   = useState([]);
  const [loading, setLoading]       = useState(true);
  const [modal, setModal]           = useState(false);
  const [editId, setEditId]         = useState(null);
  const [saving, setSaving]         = useState(false);
  const [filterEvent, setFilterEvent] = useState('');
  const [form, setForm] = useState({ eventId: '', locationId: '', showDate: '', startTime: '', endTime: '', seatsLeft: '', slotStatus: 'AVAILABLE' });

  const load = async () => {
    setLoading(true);
    try {
      const [evRes, locRes] = await Promise.all([
        getEventsByOrganiser(user.userId),
        getAllLocations(),
      ]);
      const evs  = Array.isArray(evRes.data?.data)  ? evRes.data.data  : [];
      const locs = Array.isArray(locRes.data?.data) ? locRes.data.data : [];
      setEvents(evs);
      setLocations(locs);

      if (evs.length > 0) {
        const results = await Promise.allSettled(evs.map((e) => getSlotsByEvent(e.eventId)));
        const all = results.flatMap((r) =>
          r.status === 'fulfilled' ? (Array.isArray(r.value.data?.data) ? r.value.data.data : []) : []
        );
        setSlots(all.sort((a, b) => new Date(b.showDate) - new Date(a.showDate)));
      } else {
        setSlots([]);
      }
    } catch { toast.error('Failed to load slots'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const openCreate = () => {
    setForm({ eventId: events[0]?.eventId || '', locationId: locations[0]?.locationId || '', showDate: '', startTime: '', endTime: '', seatsLeft: '', slotStatus: 'AVAILABLE' });
    setEditId(null);
    setModal(true);
  };

  const openEdit = (s) => {
    setForm({
      eventId:    s.event?.eventId    || '',
      locationId: s.location?.locationId || '',
      showDate:   s.showDate          || '',
      startTime:  s.startTime?.slice(0, 5) || '',
      endTime:    s.endTime?.slice(0, 5)   || '',
      seatsLeft:  s.seatsLeft         || '',
      slotStatus: s.slotStatus        || 'AVAILABLE',
    });
    setEditId(s.slotId);
    setModal(true);
  };

  const save = async () => {
    if (!form.eventId || !form.locationId || !form.showDate || !form.startTime) {
      toast.error('Event, venue, date and start time are required');
      return;
    }
    setSaving(true);
    try {
      const payload = {
        ...form,
        eventId:    parseInt(form.eventId),
        locationId: parseInt(form.locationId),
        seatsLeft:  form.seatsLeft ? parseInt(form.seatsLeft) : null,
      };
      if (editId) { await updateSlot(editId, payload); toast.success('Slot updated'); }
      else        { await createSlot(payload);         toast.success('Slot created! Seats auto-assigned.'); }
      setModal(false);
      load();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to save slot'); }
    finally { setSaving(false); }
  };

  const del = async (id) => {
    if (!window.confirm('Delete this slot?')) return;
    try { await deleteSlot(id); toast.success('Slot deleted'); load(); }
    catch (err) { toast.error(err.response?.data?.message || 'Delete failed'); }
  };

  const filtered = filterEvent ? slots.filter((s) => s.event?.eventId === parseInt(filterEvent)) : slots;

  return (
    <div className="container page-content" style={{ background: 'var(--bg-secondary)', minHeight: '100vh', paddingLeft: '28px', paddingRight: '28px' }}>
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
        <div>
          <h1 className="page-title">SHOW SLOTS</h1>
          <p className="page-subtitle">Schedule and manage show timings</p>
        </div>
        <button onClick={openCreate} className="btn btn-primary">➕ Add Slot</button>
      </div>

      <div style={{ display: 'flex', gap: '12px', marginBottom: '24px', alignItems: 'center', flexWrap: 'wrap' }}>
        <label className="form-label" style={{ marginBottom: 0 }}>Filter by Event:</label>
        <select className="form-input" value={filterEvent} onChange={(e) => setFilterEvent(e.target.value)} style={{ width: 'auto', minWidth: '200px' }}>
          <option value="">All Events</option>
          {events.map((e) => <option key={e.eventId} value={e.eventId}>{e.name}</option>)}
        </select>
        <span style={{ fontSize: '13px', color: 'var(--text-muted)' }}>{filtered.length} slot{filtered.length !== 1 ? 's' : ''}</span>
      </div>

      {loading ? (
        <div className="loading-center"><div className="spinner" /></div>
      ) : filtered.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state-icon">📅</div><h3>No Slots Found</h3>
          <button onClick={openCreate} className="btn btn-primary" style={{ marginTop: '16px' }}>Add First Slot</button>
        </div>
      ) : (
        <div className="table-wrap">
          <table>
            <thead><tr><th>Event</th><th>Venue</th><th>Date</th><th>Time</th><th>Seats Left</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
              {filtered.map((s) => (
                <tr key={s.slotId}>
                  <td><span style={{ fontWeight: 600 }}>{s.event?.name}</span></td>
                  <td style={{ color: 'var(--text-secondary)' }}>📍 {s.location?.locName}</td>
                  <td>{s.showDate}</td>
                  <td style={{ fontFamily: 'var(--font-mono)' }}>{s.startTime?.slice(0, 5)} – {s.endTime?.slice(0, 5)}</td>
                  <td>
                    <span style={{ fontWeight: 600, color: s.seatsLeft > 20 ? 'var(--green)' : s.seatsLeft > 0 ? 'var(--gold)' : 'var(--accent)' }}>
                      {s.seatsLeft}
                    </span>
                  </td>
                  <td><span className={`badge ${STATUS_BADGE[s.slotStatus] || 'badge-muted'}`}>{s.slotStatus}</span></td>
                  <td>
                    <div style={{ display: 'flex', gap: '6px' }}>
                      <button onClick={() => openEdit(s)} className="btn btn-secondary btn-sm">Edit</button>
                      <button onClick={() => del(s.slotId)} className="btn btn-danger btn-sm">Delete</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {modal && (
        <div className="modal-overlay" onClick={() => setModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">{editId ? 'EDIT SLOT' : 'ADD SHOW SLOT'}</h3>
              <button className="modal-close" onClick={() => setModal(false)}>✕</button>
            </div>
            <div className="form-group">
              <label className="form-label">Event *</label>
              <select className="form-input" value={form.eventId} onChange={(e) => setForm((f) => ({ ...f, eventId: e.target.value }))}>
                <option value="">Select event</option>
                {events.map((e) => <option key={e.eventId} value={e.eventId}>{e.name}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Venue *</label>
              <select className="form-input" value={form.locationId} onChange={(e) => setForm((f) => ({ ...f, locationId: e.target.value }))}>
                <option value="">Select venue</option>
                {locations.map((l) => <option key={l.locationId} value={l.locationId}>{l.locName} – {l.address}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Show Date *</label>
              <input type="date" className="form-input" value={form.showDate} onChange={(e) => setForm((f) => ({ ...f, showDate: e.target.value }))} />
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
              <div className="form-group">
                <label className="form-label">Start Time *</label>
                <input type="time" className="form-input" value={form.startTime} onChange={(e) => setForm((f) => ({ ...f, startTime: e.target.value }))} />
              </div>
              <div className="form-group">
                <label className="form-label">End Time</label>
                <input type="time" className="form-input" value={form.endTime} onChange={(e) => setForm((f) => ({ ...f, endTime: e.target.value }))} />
              </div>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
              <div className="form-group">
                <label className="form-label">Seats (blank = auto)</label>
                <input type="number" className="form-input" value={form.seatsLeft} onChange={(e) => setForm((f) => ({ ...f, seatsLeft: e.target.value }))} placeholder="Auto from venue" />
              </div>
              <div className="form-group">
                <label className="form-label">Status</label>
                <select className="form-input" value={form.slotStatus} onChange={(e) => setForm((f) => ({ ...f, slotStatus: e.target.value }))}>
                  {['AVAILABLE','HOUSEFULL','CANCELLED'].map((s) => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>
            {!editId && (
              <div style={{ padding: '10px 14px', background: 'var(--green-dim)', borderRadius: '8px', border: '1px solid rgba(0,214,143,0.2)', fontSize: '13px', color: 'var(--green)', marginBottom: '16px' }}>
                💡 Creating a slot will auto-generate seat entries from the venue's seat layout
              </div>
            )}
            <div style={{ display: 'flex', gap: '12px' }}>
              <button onClick={() => setModal(false)} className="btn btn-secondary" style={{ flex: 1 }}>Cancel</button>
              <button onClick={save} disabled={saving} className="btn btn-primary" style={{ flex: 2 }}>
                {saving ? 'Saving...' : editId ? 'Update Slot' : 'Create Slot'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminSlotsPage;
